def _validate_section_index(idx: int) -> None:
    """Raise a clear error if section index is invalid."""
    if not isinstance(idx, int):
        raise TypeError(f"Section index must be int, got {type(idx).__name__}")
    if idx < 1 or idx >= len(section_list):
        raise ValueError(
            f"Section index {idx} out of range. "
            f"Valid range is 1 to {len(section_list) - 1}."
        )


def _validate_chapter_index(idx: int) -> None:
    """Raise a clear error if chapter index is invalid."""
    if not isinstance(idx, int):
        raise TypeError(f"Chapter index must be int, got {type(idx).__name__}")
    if idx < 1 or idx >= len(chapter_list):
        raise ValueError(
            f"Chapter index {idx} out of range. "
            f"Valid range is 1 to {len(chapter_list) - 1}."
        )


def get_section(from_index: int, to_index: int) -> Dict[str, Any]:
    """
    Return a structured view of sections in [from_index, to_index].
    0<from_index<to_index<=number of sections in indian contracts act (now: 238)

    Output format:

    {
        "from": int,
        "to": int,
        "sections": [
            {"section": int, "text": str}
        ]
    }
    """
    if not isinstance(from_index, int) or not isinstance(to_index, int):
        raise TypeError("from_index and to_index must be integers")

    # allow reversed ranges
    start = min(from_index, to_index)
    end = max(from_index, to_index)

    _validate_section_index(start)
    _validate_section_index(end)

    sections = []
    for idx in range(start, end + 1):
        text = section_list[idx] if idx < len(section_list) else ""
        sections.append(
            {
                "section": idx,
                "text": text or "",
            }
        )

    return {
        "from": start,
        "to": end,
        "sections": sections,
    }


def get_chapter_section_list(chapter_idx: int) -> Dict[str, Any]:
    """
    Return all sections for a chapter in a structured way.
    0<chapter_idx<=number of chapters in indian contracts act (now: 11)
    Output format:

    {
        "chapter": int,
        "sections": [
            {"section": int, "text": str}
        ]
    }
    """
    _validate_chapter_index(chapter_idx)

    section_numbers = chapter_list[chapter_idx]
    if not isinstance(section_numbers, list):
        raise TypeError(
            f"chapter_list[{chapter_idx}] must be a list of section numbers"
        )

    sections = []
    for sec in section_numbers:
        _validate_section_index(sec)
        text = section_list[sec] if sec < len(section_list) else ""
        sections.append(
            {
                "section": sec,
                "text": text or "",
            }
        )

    return {
        "chapter": chapter_idx,
        "sections": sections,
    }
